@app.route("/users/active", methods=["POST"])
def set_active_users():
    payload = request.get_json(silent=True) or {}
    count = int(payload.get("count", 0))
    ACTIVE_USERS.set(count)
    return jsonify({"active_users": count})


@app.route("/orders", methods=["POST"])
def create_order():
    payload = request.get_json(silent=True) or {}
    value = float(payload.get("value", random.uniform(20, 500)))
    product = payload.get("product", "default")
    payment_delay = float(payload.get("payment_delay", random.uniform(0.05, 0.5)))
    success = bool(payload.get("success", True))

    time.sleep(payment_delay)
    PAYMENT_PROCESSING_TIME.observe(payment_delay)
    ORDER_VALUE.observe(value)

    if success:
        ORDERS_CREATED.labels("success").inc()
        INVENTORY_LEVEL.labels(product).dec()
        return jsonify({
            "status": "created",
            "product": product,
            "value": value
        }), 201

    ORDERS_CREATED.labels("failed").inc()
    return jsonify({
        "status": "failed",
        "product": product,
        "value": value
    }), 400


@app.route("/inventory/<product>", methods=["POST"])
def update_inventory(product):
    payload = request.get_json(silent=True) or {}
    level = float(payload.get("level", 0))
    INVENTORY_LEVEL.labels(product).set(level)
    return jsonify({"product": product, "inventory_level": level})


